1	// R10.5 — Taxonomy reclassification worker.
2	//
3	// Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R10.5 task 4.
4	//
5	// Consumes approved taxonomy_proposals that the admin-action in
6	// apps/web/app/admin/taxonomy/_actions.ts defers with:
7	//   afterState.queuedFor = 'taxonomy-reclassification-worker'
8	//
9	// Applies the structural mutation that the proposal describes, then writes a
10	// taxonomy_change_log row with changeType 'reclassification_applied_*' so the
11	// proposal is never re-processed.
12	//
13	// Governance invariants (see docs/oracle/07-knowledge-segmentation.md):
14	//   - NEVER auto-mutates an un-approved proposal. status must be 'approved'.
15	//   - NEVER touches claims, claim_evidence, or extraction tables.
16	//   - NEVER deletes taxonomy rows — only inserts, updates (review_status),
17	//     and claim_sub_topics re-assignments.
18	//   - complex proposals (split_top_domain, split_sub_topic) require human
19	//     judgment about which claims go where; they are logged as
20	//     'manual_intervention_required' and skipped.
21	//
22	// Trigger.dev auto-discovers this file via dirs: ['./src/trigger'] in
23	// trigger.config.ts — no explicit registration needed.
24	
25	import { task } from '@trigger.dev/sdk/v3';
26	import { and, eq, inArray, notInArray, sql } from 'drizzle-orm';
27	import { z } from 'zod';
28	import { getDirectDb } from '@oracle/db/client';
29	import {
30	  claimSubTopics,
31	  claimTopDomains,
32	  jobRuns,
33	  knowledgeSubTopics,
34	  knowledgeTopDomains,
35	  taxonomyChangeLog,
36	  taxonomyProposals,
37	} from '@oracle/db';
38	
39	// ─────────────────────────────────────────────────────────────────────────
40	// Payload types
41	// ─────────────────────────────────────────────────────────────────────────
42	
43	const ManualTriggerPayload = z.object({
44	  /** Only reclassify proposals of this type. Omit to process all pending. */
45	  proposalType: z.string().optional(),
46	  /** Dry-run: find pending proposals but do not apply mutations. */
47	  dryRun: z.boolean().optional(),
48	});
49	
50	// Loose type for the JSONB payload stored in taxonomy_proposals.
51	// Each handler narrows further.
52	type ProposalPayload = Record<string, unknown>;
53	
54	// ─────────────────────────────────────────────────────────────────────────
55	// Find pending reclassifications
56	// ─────────────────────────────────────────────────────────────────────────
57	
58	type PendingProposal = {
59	  id: string;
60	  proposalType: string;
61	  payload: ProposalPayload;
62	};
63	
64	async function findPendingReclassifications(
65	  db: ReturnType<typeof getDirectDb>,
66	  proposalTypeFilter?: string,
67	): Promise<PendingProposal[]> {
68	  // Find approved proposals that have the "queuedFor" change_log row but NOT
69	  // a "reclassification_applied_*" row yet.
70	  const result = await db.execute(sql`
71	    SELECT tp.id, tp.proposal_type, tp.payload
72	    FROM taxonomy_proposals tp
73	    WHERE tp.status = 'approved'
74	      AND tp.proposal_type != 'create_top_domain'
75	      ${proposalTypeFilter ? sql`AND tp.proposal_type = ${proposalTypeFilter}` : sql``}
76	      AND EXISTS (
77	        SELECT 1 FROM taxonomy_change_log cl
78	        WHERE cl.proposal_id = tp.id
79	          AND cl.change_type LIKE 'approve_pending_reclassification_%'
80	      )
81	      AND NOT EXISTS (
82	        SELECT 1 FROM taxonomy_change_log cl
83	        WHERE cl.proposal_id = tp.id
84	          AND cl.change_type LIKE 'reclassification_applied_%'
85	      )
86	    ORDER BY tp.created_at ASC
87	    LIMIT 50
88	  `);
89	
90	  return (result as unknown as Array<{ id: string; proposal_type: string; payload: unknown }>).map(
91	    (r) => ({
92	      id: r.id,
93	      proposalType: r.proposal_type,
94	      payload: (r.payload ?? {}) as ProposalPayload,
95	    }),
96	  );
97	}
98	
99	// ─────────────────────────────────────────────────────────────────────────
100	// Proposal handlers
101	// ─────────────────────────────────────────────────────────────────────────
102	
103	type HandlerResult =
104	  | { applied: true; afterState: unknown }
105	  | { applied: false; reason: string };
106	
107	/** create_sub_topic: INSERT knowledge_sub_topics + link representative claims. */
108	async function handleCreateSubTopic(
109	  db: ReturnType<typeof getDirectDb>,
110	  payload: ProposalPayload,
111	): Promise<HandlerResult> {
112	  const topDomainId = payload.topDomainId as string | undefined;
113	  const proposedName = payload.proposedName as string | undefined;
114	  const purpose = payload.oneSentencePurpose as string | undefined;
115	  const centroid = payload.clusterCentroid as number[] | undefined;
116	  const representativeClaimIds = (payload.representativeClaimIds as string[] | undefined) ?? [];
117	
118	  if (!topDomainId || !proposedName) {
119	    return { applied: false, reason: 'payload missing topDomainId or proposedName' };
120	  }
121	
122	  const [inserted] = await db
123	    .insert(knowledgeSubTopics)
124	    .values({
125	      topDomainId,
126	      name: proposedName,
127	      description: purpose ?? null,
128	      centroid: centroid ?? null,
129	      memberCount: representativeClaimIds.length,
130	      reviewStatus: 'approved',
131	    })
132	    .onConflictDoNothing()
133	    .returning({ id: knowledgeSubTopics.id });
134	
135	  if (!inserted) {
136	    return {
137	      applied: false,
138	      reason: `knowledge_sub_topic (${topDomainId}, "${proposedName}") already exists — skipping`,
139	    };
140	  }
141	
142	  if (representativeClaimIds.length > 0) {
143	    await db
144	      .insert(claimSubTopics)
145	      .values(
146	        representativeClaimIds.map((claimId) => ({
147	          claimId,
148	          subTopicId: inserted.id,
149	          assignmentReason: 'cluster_seed',
150	          assignmentConfidence: '0.800',
151	        })),
152	      )
153	      .onConflictDoNothing();
154	  }
155	
156	  return {
157	    applied: true,
158	    afterState: {
159	      subTopicId: inserted.id,
160	      topDomainId,
161	      name: proposedName,
162	      linkedClaims: representativeClaimIds.length,
163	    },
164	  };
165	}
