167	/** reassign_claims: move claims from one sub-topic to another. */
168	async function handleReassignClaims(
169	  db: ReturnType<typeof getDirectDb>,
170	  payload: ProposalPayload,
171	): Promise<HandlerResult> {
172	  const fromSubTopicId = payload.fromSubTopicId as string | undefined;
173	  const toSubTopicId = payload.toSubTopicId as string | undefined;
174	  const claimIds = payload.claimIds as string[] | undefined;
175	
176	  if (!fromSubTopicId || !toSubTopicId) {
177	    return { applied: false, reason: 'payload missing fromSubTopicId or toSubTopicId' };
178	  }
179	
180	  const targetExists = await db
181	    .select({ id: knowledgeSubTopics.id })
182	    .from(knowledgeSubTopics)
183	    .where(eq(knowledgeSubTopics.id, toSubTopicId))
184	    .limit(1);
185	  if (!targetExists.length) {
186	    return { applied: false, reason: `target sub-topic ${toSubTopicId} not found` };
187	  }
188	
189	  const whereClause =
190	    claimIds && claimIds.length > 0
191	      ? and(eq(claimSubTopics.subTopicId, fromSubTopicId), inArray(claimSubTopics.claimId, claimIds))
192	      : eq(claimSubTopics.subTopicId, fromSubTopicId);
193	
194	  // Re-point existing rows; skip claims already in the target.
195	  const alreadyInTarget = await db
196	    .select({ claimId: claimSubTopics.claimId })
197	    .from(claimSubTopics)
198	    .where(eq(claimSubTopics.subTopicId, toSubTopicId));
199	  const skipIds = alreadyInTarget.map((r) => r.claimId);
200	
201	  const finalWhere =
202	    skipIds.length > 0
203	      ? and(whereClause, notInArray(claimSubTopics.claimId, skipIds))
204	      : whereClause;
205	
206	  const updated = await db
207	    .update(claimSubTopics)
208	    .set({ subTopicId: toSubTopicId })
209	    .where(finalWhere)
210	    .returning({ claimId: claimSubTopics.claimId });
211	
212	  return {
213	    applied: true,
214	    afterState: { fromSubTopicId, toSubTopicId, reassignedCount: updated.length },
215	  };
216	}
