218	/** merge_sub_topics: move all members of source into target, then retire source. */
219	async function handleMergeSubTopics(
220	  db: ReturnType<typeof getDirectDb>,
221	  payload: ProposalPayload,
222	): Promise<HandlerResult> {
223	  const sourceSubTopicId = payload.sourceSubTopicId as string | undefined;
224	  const targetSubTopicId = payload.targetSubTopicId as string | undefined;
225	
226	  if (!sourceSubTopicId || !targetSubTopicId) {
227	    return { applied: false, reason: 'payload missing sourceSubTopicId or targetSubTopicId' };
228	  }
229	  if (sourceSubTopicId === targetSubTopicId) {
230	    return { applied: false, reason: 'source and target sub-topic IDs are the same' };
231	  }
232	
233	  // Move claims not already in target.
234	  const alreadyInTarget = await db
235	    .select({ claimId: claimSubTopics.claimId })
236	    .from(claimSubTopics)
237	    .where(eq(claimSubTopics.subTopicId, targetSubTopicId));
238	  const skipIds = alreadyInTarget.map((r) => r.claimId);
239	
240	  const moveWhere =
241	    skipIds.length > 0
242	      ? and(eq(claimSubTopics.subTopicId, sourceSubTopicId), notInArray(claimSubTopics.claimId, skipIds))
243	      : eq(claimSubTopics.subTopicId, sourceSubTopicId);
244	
245	  const moved = await db
246	    .update(claimSubTopics)
247	    .set({ subTopicId: targetSubTopicId })
248	    .where(moveWhere)
249	    .returning({ claimId: claimSubTopics.claimId });
250	
251	  // Delete any leftover rows pointing at source (duplicates that were in target).
252	  await db
253	    .delete(claimSubTopics)
254	    .where(eq(claimSubTopics.subTopicId, sourceSubTopicId));
255	
256	  // Retire source sub-topic.
257	  await db
258	    .update(knowledgeSubTopics)
259	    .set({ reviewStatus: 'retired' })
260	    .where(eq(knowledgeSubTopics.id, sourceSubTopicId));
261	
262	  return {
263	    applied: true,
264	    afterState: {
265	      sourceSubTopicId,
266	      targetSubTopicId,
267	      movedCount: moved.length,
268	      sourceStatus: 'retired',
269	    },
270	  };
271	}
