273	/** retire_sub_topic: mark retired, detach all claim_sub_topics rows. */
274	async function handleRetireSubTopic(
275	  db: ReturnType<typeof getDirectDb>,
276	  payload: ProposalPayload,
277	): Promise<HandlerResult> {
278	  const subTopicId = payload.subTopicId as string | undefined;
279	  if (!subTopicId) {
280	    return { applied: false, reason: 'payload missing subTopicId' };
281	  }
282	
283	  const detached = await db
284	    .delete(claimSubTopics)
285	    .where(eq(claimSubTopics.subTopicId, subTopicId))
286	    .returning({ claimId: claimSubTopics.claimId });
287	
288	  await db
289	    .update(knowledgeSubTopics)
290	    .set({ reviewStatus: 'retired' })
291	    .where(eq(knowledgeSubTopics.id, subTopicId));
292	
293	  return {
294	    applied: true,
295	    afterState: { subTopicId, detachedClaimsCount: detached.length, status: 'retired' },
296	  };
297	}
