363	// ─────────────────────────────────────────────────────────────────────────
364	// Main dispatch
365	// ─────────────────────────────────────────────────────────────────────────
366	
367	async function applyProposal(
368	  db: ReturnType<typeof getDirectDb>,
369	  proposal: PendingProposal,
370	  dryRun: boolean,
371	): Promise<{ proposalId: string; changeType: string; applied: boolean; note: string }> {
372	  if (dryRun) {
373	    return {
374	      proposalId: proposal.id,
375	      changeType: `dry_run_${proposal.proposalType}`,
376	      applied: false,
377	      note: 'dry-run — no mutation applied',
378	    };
379	  }
380	
381	  // Run the structural mutation AND the taxonomy_change_log row inside a single
382	  // transaction so a partial failure mid-handler can't leave the taxonomy moved
383	  // without an 'applied' log row (or vice versa) — the whole thing rolls back.
384	  const result = await db.transaction<HandlerResult>(async (tx) => {
385	    let r: HandlerResult;
386	    switch (proposal.proposalType) {
387	      case 'create_sub_topic':
388	        r = await handleCreateSubTopic(tx, proposal.payload);
389	        break;
390	      case 'reassign_claims':
391	        r = await handleReassignClaims(tx, proposal.payload);
392	        break;
393	      case 'merge_sub_topics':
394	        r = await handleMergeSubTopics(tx, proposal.payload);
395	        break;
396	      case 'retire_sub_topic':
397	        r = await handleRetireSubTopic(tx, proposal.payload);
398	        break;
399	      case 'merge_top_domains':
400	        r = await handleMergeTopDomains(tx, proposal.payload);
401	        break;
402	      case 'split_top_domain':
403	      case 'split_sub_topic':
404	        r = {
405	          applied: false,
406	          reason: `${proposal.proposalType} requires manual admin intervention — claim-level split cannot be automated safely.`,
407	        };
408	        break;
409	      default:
410	        r = { applied: false, reason: `unknown proposal type: ${proposal.proposalType}` };
411	    }
412	
413	    const ct = r.applied
414	      ? `reclassification_applied_${proposal.proposalType}`
415	      : `reclassification_skipped_${proposal.proposalType}`;
416	
417	    await tx.insert(taxonomyChangeLog).values({
418	      changeType: ct,
419	      beforeState: { proposalId: proposal.id, proposalType: proposal.proposalType },
420	      afterState: r.applied ? r.afterState : { reason: r.reason },
421	      reason: r.applied ? 'Applied by taxonomy-reclassification worker' : r.reason,
422	      proposalId: proposal.id,
423	    });
424	
425	    return r;
426	  });
427	
428	  const changeType = result.applied
429	    ? `reclassification_applied_${proposal.proposalType}`
430	    : `reclassification_skipped_${proposal.proposalType}`;
431	
432	  return {
433	    proposalId: proposal.id,
434	    changeType,
435	    applied: result.applied,
436	    note: result.applied ? 'applied' : result.reason,
437	  };
438	}
