440	// ─────────────────────────────────────────────────────────────────────────
441	// Task
442	// ─────────────────────────────────────────────────────────────────────────
443	
444	export const taxonomyReclassificationTask = task({
445	  id: 'taxonomy-reclassification',
446	  maxDuration: 60 * 5,
447	  run: async (payload: z.infer<typeof ManualTriggerPayload>, { ctx }) => {
448	    const parsed = ManualTriggerPayload.parse(payload);
449	    const db = getDirectDb();
450	
451	    const [jobRun] = await db
452	      .insert(jobRuns)
453	      .values({
454	        triggerRunId: ctx.run.id,
455	        jobType: 'taxonomy-reclassification',
456	        status: 'running',
457	        startedAt: new Date(),
458	        inputJson: { proposalType: parsed.proposalType ?? null, dryRun: parsed.dryRun ?? false },
459	      })
460	      .returning({ id: jobRuns.id });
461	    if (!jobRun) throw new Error('[taxonomy-reclassification] failed to insert job_runs row');
462	
463	    try {
464	      const pending = await findPendingReclassifications(db, parsed.proposalType);
465	
466	      const results = [];
467	      for (const proposal of pending) {
468	        const r = await applyProposal(db, proposal, parsed.dryRun ?? false);
469	        results.push(r);
470	      }
471	
472	      const appliedCount = results.filter((r) => r.applied).length;
473	      const skippedCount = results.length - appliedCount;
474	
475	      const output = {
476	        ok: true as const,
477	        dryRun: parsed.dryRun ?? false,
478	        proposalsFound: pending.length,
479	        proposalsApplied: appliedCount,
480	        proposalsSkipped: skippedCount,
481	        results,
482	      };
483	
484	      await db
485	        .update(jobRuns)
486	        .set({ status: 'complete', finishedAt: new Date(), outputJson: output })
487	        .where(sql`id = ${jobRun.id}`);
488	
489	      return output;
490	    } catch (err) {
491	      await db
492	        .update(jobRuns)
493	        .set({
494	          status: 'failed',
495	          finishedAt: new Date(),
496	          error: err instanceof Error ? err.message : String(err),
497	        })
498	        .where(sql`id = ${jobRun.id}`);
499	      throw err;
500	    }
501	  },
502	});
