152	// ─────────────────────────────────────────────────────────────────────────
153	// Cluster naming via cheap LLM call
154	// ─────────────────────────────────────────────────────────────────────────
155	
156	type ClusterName = { name: string; purpose: string };
157	
158	const ClusterNameSchema = z.object({
159	  name: z.string(),
160	  purpose: z.string(),
161	});
162	
163	async function nameCluster(
164	  client: OracleAIClient,
165	  domainId: string,
166	  claimSummaries: string[],
167	): Promise<ClusterName> {
168	  const topSummaries = claimSummaries.slice(0, 5);
169	  const listText = topSummaries.map((s, i) => `${i + 1}. ${s}`).join('\n');
170	
171	  const result = await client.runObject<ClusterName>({
172	    taskType: 'admin_explanation',
173	    routeId: CLUSTER_NAMING_ROUTE_ID,
174	    promptVersion: CLUSTER_NAMING_PROMPT_VERSION,
175	    schema: ClusterNameSchema,
176	    blocks: [
177	      makeBlock({
178	        id: 'cluster-naming-system',
179	        label: 'Cluster naming system prompt',
180	        kind: 'stable_system',
181	        content: `You are a taxonomy assistant for a product licensing and manufacturing company.
182	Given a set of claim summaries that cluster together within a knowledge domain, your job is to assign a short descriptive sub-topic name and one-sentence purpose.
183	
184	Rules:
185	- Name: 2–6 words, title case, no punctuation at the end.
186	- Purpose: one sentence, plain English, describes what claims in this sub-topic have in common.`,
187	        // Stable system instructions are identical across every cluster/domain
188	        // naming call, so this prefix is cache-eligible.
189	        cacheEligible: true,
190	        reasonIncluded: 'cluster naming stable system',
191	      }),
192	      makeBlock({
193	        id: 'cluster-naming-input',
194	        label: 'Claim summaries for this cluster',
195	        kind: 'dynamic_input',
196	        content: `Domain: ${domainId}\n\nClaim summaries:\n${listText}`,
197	        reasonIncluded: `${topSummaries.length} representative claims`,
198	      }),
199	    ],
200	  });
201	
202	  if (result.validation.ok) {
203	    const obj = result.object;
204	    if (obj.name.trim() && obj.purpose.trim()) {
205	      return { name: obj.name, purpose: obj.purpose };
206	    }
207	  }
208	
209	  return {
210	    name: `${domainId.replace(/_/g, ' ')} cluster`,
211	    purpose: `A group of related claims within the ${domainId} domain discovered by automated clustering.`,
212	  };
213	}
