215	// ─────────────────────────────────────────────────────────────────────────
216	// Per-domain clustering
217	// ─────────────────────────────────────────────────────────────────────────
218	
219	type ClaimRow = { id: string; summary: string; embedding: number[] };
220	
221	async function processReadyDomain(
222	  db: ReturnType<typeof getDirectDb>,
223	  client: OracleAIClient,
224	  domainId: string,
225	): Promise<number> {
226	  // Load approved claims with non-null embeddings for this domain.
227	  const rows = await db
228	    .select({
229	      id: claims.id,
230	      summary: claims.summary,
231	      embedding: claims.embedding,
232	    })
233	    .from(claims)
234	    .innerJoin(claimTopDomains, eq(claimTopDomains.claimId, claims.id))
235	    .where(
236	      and(
237	        eq(claimTopDomains.topDomainId, domainId),
238	        eq(claims.status, 'approved'),
239	        isNotNull(claims.embedding),
240	      ),
241	    )
242	    .orderBy(desc(claims.impactScore))
243	    .limit(500);
244	
245	  const claimRows = rows.filter((r): r is ClaimRow => r.embedding !== null && r.embedding.length > 0);
246	  if (claimRows.length < MIN_CLUSTER_SIZE) return 0;
247	
248	  const k = Math.min(MAX_K, Math.max(2, Math.round(Math.sqrt(claimRows.length / 4))));
249	  const vectors = claimRows.map((r) => r.embedding);
250	  const clusters = kMeans(vectors, k);
251	
252	  // Load existing approved/pending sub-topic centroids for this domain to
253	  // detect novelty. Skip clusters that are already represented.
254	  const existingSubTopics = await db
255	    .select({ centroid: knowledgeSubTopics.centroid })
256	    .from(knowledgeSubTopics)
257	    .where(eq(knowledgeSubTopics.topDomainId, domainId));
258	
259	  const existingCentroids = existingSubTopics
260	    .map((st) => st.centroid)
261	    .filter((c): c is number[] => c !== null && c.length > 0);
262	
263	  // Also dedupe against still-PENDING create_sub_topic proposals for this
264	  // domain. Without this, repeated re-evaluation runs (before an admin acts on
265	  // the queue) flood the queue with duplicate proposals for the same cluster.
266	  const pendingProposalRows = await db
267	    .select({ payload: taxonomyProposals.payload })
268	    .from(taxonomyProposals)
269	    .where(
270	      and(
271	        eq(taxonomyProposals.proposalType, 'create_sub_topic'),
272	        eq(taxonomyProposals.status, 'pending'),
273	      ),
274	    );
275	  const pendingCentroids = pendingProposalRows
276	    .map((r) => {
277	      const p = (r.payload ?? {}) as { topDomainId?: unknown; clusterCentroid?: unknown };
278	      if (p.topDomainId !== domainId) return null;
279	      const centroid = p.clusterCentroid;
280	      return Array.isArray(centroid) && centroid.every((n) => typeof n === 'number')
281	        ? (centroid as number[])
282	        : null;
283	    })
284	    .filter((c): c is number[] => c !== null && c.length > 0);
285	  const noveltyCentroids = [...existingCentroids, ...pendingCentroids];
286	
287	  let proposalsWritten = 0;
288	
289	  for (const cluster of clusters) {
290	    if (cluster.memberIndices.length < MIN_CLUSTER_SIZE) continue;
291	
292	    // Novelty check: skip if too similar to an existing sub-topic OR an
293	    // already-pending create_sub_topic proposal for this domain.
294	    const maxExistingSim = noveltyCentroids.reduce(
295	      (max, existing) => Math.max(max, cosineSimilarity(cluster.centroid, existing)),
296	      -Infinity,
297	    );
298	    if (maxExistingSim >= NOVELTY_COSINE_THRESHOLD) continue;
299	
300	    // Build evidence list (top members by original claim order, already
301	    // sorted desc by impact_score above).
302	    const memberClaims = cluster.memberIndices
303	      .sort((a, b) => a - b)
304	      .slice(0, 5)
305	      .map((i) => claimRows[i]!)
306	      .filter(Boolean);
307	
308	    const summaries = memberClaims.map((c) => c.summary);
309	    let clusterName: ClusterName;
310	    let modelRunId: string | null = null;
311	    const callStart = Date.now();
312	
313	    try {
314	      clusterName = await nameCluster(client, domainId, summaries);
315	      const latencyMs = Date.now() - callStart;
316	
317	      const [mr] = await db
318	        .insert(modelRuns)
319	        .values({
320	          taskType: 'taxonomy-cluster-naming',
321	          model: 'gemini-2.5-flash',
322	          provider: 'vertex',
323	          promptVersion: CLUSTER_NAMING_PROMPT_VERSION,
324	          latencyMs,
325	          success: true,
326	        })
327	        .returning({ id: modelRuns.id });
328	      modelRunId = mr?.id ?? null;
329	    } catch {
330	      // Naming failed — use a generic fallback so the cluster isn't lost.
331	      const latencyMs = Date.now() - callStart;
332	      clusterName = {
333	        name: `${domainId.replace(/_/g, ' ')} cluster`,
334	        purpose: `A group of ${cluster.memberIndices.length} claims within ${domainId} discovered by automated clustering.`,
335	      };
336	      await db.insert(modelRuns).values({
337	        taskType: 'taxonomy-cluster-naming',
338	        model: 'gemini-2.5-flash',
339	        provider: 'vertex',
340	        promptVersion: CLUSTER_NAMING_PROMPT_VERSION,
341	        latencyMs,
342	        success: false,
343	        error: 'cluster naming LLM call failed',
344	      });
345	    }
346	
347	    // Build proposal payload per TaxonomyProposalPayload contract in
348	    // docs/oracle/07-knowledge-segmentation.md.
349	    // Extra fields (topDomainId, clusterCentroid, representativeClaimIds) are
350	    // not part of the base contract but are consumed by the
351	    // taxonomy-reclassification worker to create the sub-topic row.
352	    const payload = {
353	      proposedName: clusterName.name,
354	      oneSentencePurpose: clusterName.purpose,
355	      proposalReason: `Automated k-means clustering (k=${k}) on ${claimRows.length} approved claim embeddings in domain "${domainId}" identified a cluster of ${cluster.memberIndices.length} claims with no sufficiently similar existing sub-topic (max existing centroid similarity: ${maxExistingSim === -Infinity ? 'none' : maxExistingSim.toFixed(3)}).`,
356	      topDomainId: domainId,
357	      clusterCentroid: cluster.centroid,
358	      representativeEvidence: memberClaims.map((c) => ({
359	        sourceType: 'claim' as const,
360	        sourceId: c.id,
361	        shortSnippet: c.summary.slice(0, 200),
362	        whyRepresentative: 'Selected as top member of this cluster by claim order (impact score desc)',
363	      })),
364	      representativeClaimIds: memberClaims.map((c) => c.id),
365	      commonEntities: [],
366	      affectedCounts: { claims: cluster.memberIndices.length },
367	      suggestedRetrievalExclusions: [],
368	      recommendedAction: 'approve' as const,
369	      recommendedActionReason: `Cluster has ${cluster.memberIndices.length} members and appears meaningfully distinct from existing sub-topics.`,
370	      confidence: Math.min(0.95, 0.5 + cluster.memberIndices.length / 50),
371	    };
372	
373	    await db.insert(taxonomyProposals).values({
374	      proposalType: 'create_sub_topic',
375	      payload,
376	      proposedByModelRunId: modelRunId ?? undefined,
377	      status: 'pending',
378	    });
379	
380	    proposalsWritten++;
381	  }
382	
383	  return proposalsWritten;
384	}
