390	const ManualTriggerPayload = z.object({
391	  topDomainId: z.string().optional(),
392	  activationThreshold: z.number().int().positive().optional(),
393	});
394	
395	type DomainCountRow = {
396	  top_domain_id: string;
397	  claim_count: number;
398	};
399	
400	async function runReevaluation(args: {
401	  triggerRunId: string;
402	  trigger: 'scheduled' | 'manual';
403	  topDomainFilter?: string;
404	  activationThreshold: number;
405	}): Promise<{
406	  ok: true;
407	  trigger: 'scheduled' | 'manual';
408	  totalClaims: number;
409	  domainsScanned: number;
410	  domainsReady: number;
411	  domainsBelowThreshold: number;
412	  proposalsWritten: number;
413	  note: string;
414	}> {
415	  const db = getDirectDb();
416	  const client = buildOracleClient();
417	
418	  const [jobRun] = await db
419	    .insert(jobRuns)
420	    .values({
421	      triggerRunId: args.triggerRunId,
422	      jobType: 'taxonomy-reevaluation',
423	      status: 'running',
424	      startedAt: new Date(),
425	      inputJson: {
426	        trigger: args.trigger,
427	        topDomainFilter: args.topDomainFilter ?? null,
428	        activationThreshold: args.activationThreshold,
429	      },
430	    })
431	    .returning({ id: jobRuns.id });
432	  if (!jobRun) throw new Error('[taxonomy-reevaluation] failed to insert job_runs row');
433	
434	  try {
435	    const domainFilter = args.topDomainFilter ? sql`AND d.id = ${args.topDomainFilter}` : sql``;
436	    const result = await db.execute(sql`
437	      SELECT d.id AS top_domain_id,
438	             COALESCE((
439	               SELECT COUNT(DISTINCT ctd.claim_id)
440	               FROM claim_top_domains ctd
441	               JOIN claims c ON c.id = ctd.claim_id
442	               WHERE ctd.top_domain_id = d.id
443	                 AND c.status = 'approved'
444	                 AND c.embedding IS NOT NULL
445	             ), 0) AS claim_count
446	      FROM knowledge_top_domains d
447	      WHERE d.is_active = true
448	      ${domainFilter}
449	      ORDER BY d.display_order
450	    `);
451	    const rows = [...result] as unknown as DomainCountRow[];
452	
453	    const totalClaims = rows.reduce((sum, r) => sum + Number(r.claim_count), 0);
454	    const readyRows = rows.filter((r) => Number(r.claim_count) >= args.activationThreshold);
455	    const domainsReady = readyRows.length;
456	    const domainsBelowThreshold = rows.length - domainsReady;
457	
458	    let proposalsWritten = 0;
459	    const perDomainResults: Record<string, { claimsWithEmbeddings: number; proposals: number }> = {};
460	
461	    for (const row of readyRows) {
462	      const written = await processReadyDomain(db, client, row.top_domain_id);
463	      proposalsWritten += written;
464	      perDomainResults[row.top_domain_id] = {
465	        claimsWithEmbeddings: Number(row.claim_count),
466	        proposals: written,
467	      };
468	    }
469	
470	    const note =
471	      domainsReady === 0
472	        ? `No active domain has reached the ${args.activationThreshold}-claim activation threshold (counting only approved claims with embeddings). Sub-topic clustering remains disabled.`
473	        : `Clustered ${domainsReady} of ${rows.length} active domains. Wrote ${proposalsWritten} create_sub_topic proposal(s) for admin review.`;
474	
475	    const output = {
476	      ok: true as const,
477	      trigger: args.trigger,
478	      totalClaims,
479	      domainsScanned: rows.length,
480	      domainsReady,
481	      domainsBelowThreshold,
482	      proposalsWritten,
483	      note,
484	    };
485	
486	    await db
487	      .update(jobRuns)
488	      .set({
489	        status: 'complete',
490	        finishedAt: new Date(),
491	        outputJson: { ...output, perDomainCounts: rows, perDomainResults },
492	      })
493	      .where(sql`id = ${jobRun.id}`);
494	
495	    return output;
496	  } catch (err) {
497	    await db
498	      .update(jobRuns)
499	      .set({
500	        status: 'failed',
501	        finishedAt: new Date(),
502	        error: err instanceof Error ? err.message : String(err),
503	      })
504	      .where(sql`id = ${jobRun.id}`);
505	    throw err;
506	  }
507	}
